#!/usr/bin/env perl

use strict;
use warnings;

my $redirect_url = '';

if (exists($ENV{'QUERY_STRING'}) && $ENV{'QUERY_STRING'} =~ /next=([^&]+)/) {
    $redirect_url = $1;
}

# Allowlist valid redirect destinations or use server-side route names/IDs rather than raw URLs.
if ($redirect_url !~ m!^https?://! && $redirect_url !~ m!/!) {
